            <tr>
                <td>{{ option.id }}</td>
                <td>{{ option.nomOption }}</td>
                <td>
                    <a href=\"{{ path(\x27options_show\x27, {\x27id\x27: option.id}) }}\">
                        <button class=\"btn btn-outline-dark\">Voir</button>
                    </a>
